  "apiHost": "api.notion.com",
  "basePath": "/v1",
  "scopeMap": [
    {
      "method": "POST",
      "pathPattern": "/v1/databases",
      "sufficientScopes": ["insert_content"],
      "description": "Create a database"
    },
    {
      "method": "GET",
      "pathPattern": "/v1/databases/*",
      "sufficientScopes": ["read_content"],
      "description": "Retrieve a database"
    },
    {
      "method": "PATCH",
      "pathPattern": "/v1/databases/*",
      "sufficientScopes": ["update_content"],
      "description": "Update a database"
    },
    {
