      "pathPattern": "/v1/databases/*/query",
      "sufficientScopes": ["read_content"],
      "description": "Query a database"
    },
    {
      "method": "POST",
      "pathPattern": "/v1/pages",
      "sufficientScopes": ["insert_content"],
      "description": "Create a page"
    },
    {
      "method": "GET",
      "pathPattern": "/v1/pages/*",
      "sufficientScopes": ["read_content"],
      "description": "Retrieve a page"
    },
    {
      "method": "PATCH",
      "pathPattern": "/v1/pages/*",
      "sufficientScopes": ["update_content"],
      "description": "Update page properties"
    },
    {
      "method": "DELETE",
      "pathPattern": "/v1/pages/*",
      "sufficientScopes": ["update_content"],
      "description": "Trash a page (archive)"
    },
    {
      "method": "PUT",
      "pathPattern": "/v1/pages/*",
      "sufficientScopes": ["update_content"],
      "description": "Move a page to a new parent"
    },
    {
      "method": "GET",
      "pathPattern": "/v1/pages/*/properties/*",
      "sufficientScopes": ["read_content"],
      "description": "Retrieve a page property item"
    },
    {
      "method": "GET",
      "pathPattern": "/v1/pages/*/markdown",
      "sufficientScopes": ["read_content"],
      "description": "Retrieve page content as markdown"
    },
    {
      "method": "PATCH",
      "pathPattern": "/v1/pages/*/markdown",
      "sufficientScopes": ["update_content"],
      "description": "Update page content using markdown"
    },
    {
      "method": "GET",
      "pathPattern": "/v1/blocks/*",
      "sufficientScopes": ["read_content"],
      "description": "Retrieve a block"
    },
    {
      "method": "GET",
      "pathPattern": "/v1/blocks/*/children",
      "sufficientScopes": ["read_content"],
      "description": "Retrieve block children"
    },
    {
      "method": "PATCH",
      "pathPattern": "/v1/blocks/*/children",
      "sufficientScopes": ["insert_content"],
      "description": "Append block children"
    },
    {
      "method": "PATCH",
      "pathPattern": "/v1/blocks/*",
      "sufficientScopes": ["update_content"],
      "description": "Update a block"
    },
    {
      "method": "DELETE",
      "pathPattern": "/v1/blocks/*",
      "sufficientScopes": ["update_content"],
      "description": "Delete a block"
    },
    {
      "method": "GET",
      "pathPattern": "/v1/users",
      "sufficientScopes": ["read_user_information"],
      "description": "List all users"
    },
    {
      "method": "GET",
      "pathPattern": "/v1/users/*",
      "sufficientScopes": ["read_user_information"],
      "description": "Retrieve a user"
    },
    {
      "method": "GET",
      "pathPattern": "/v1/users/me",
      "sufficientScopes": ["read_user_information"],
      "description": "Retrieve the bot user (token owner)"
    },
    {
      "method": "POST",
      "pathPattern": "/v1/search",
      "sufficientScopes": ["read_content"],
      "description": "Search pages and databases"
    },
    {
      "method": "GET",
      "pathPattern": "/v1/pages/*/comments",
      "sufficientScopes": ["read_comments"],
      "description": "List comments on a page"
    },
    {
      "method": "GET",
      "pathPattern": "/v1/comments/*",
      "sufficientScopes": ["read_comments"],
      "description": "Retrieve a comment"
    },
    {
      "method": "POST",
      "pathPattern": "/v1/comments",
      "sufficientScopes": ["insert_comments"],
      "description": "Create a comment"
    },
    {
      "method": "PATCH",
      "pathPattern": "/v1/comments/*",
      "sufficientScopes": ["update_content"],
      "description": "Update a comment"
    },
    {
      "method": "DELETE",
      "pathPattern": "/v1/comments/*",
      "sufficientScopes": ["update_content"],
      "description": "Delete a comment"
    }
  ],
  "allScopes": [
    "read_content",
    "update_content",
    "insert_content",
    "read_user_information",
    "read_comments",
    "insert_comments"
  ]
